async function fetchMandiRates(state = "Chhattisgarh", district = "Raipur", commodity = "") {
	const cacheKey = `kisanbaba_mandi_${state}_${district}_${commodity}`;
	const cached = localStorage.getItem(cacheKey);
	if (cached) {
		const parsed = JSON.parse(cached);
		if (Date.now() - parsed.timestamp < 36e5) return parsed.data;
	}
	try {
		let url = `/api/ogd/resource/9ef84268-d588-465a-a308-a864a43d0070?api-key=579b464db66ec23bdd000001b69eb7b556b74d4a7d665f83c03f6fe2&format=json&limit=50&filters[state]=${encodeURIComponent(state)}&filters[district]=${encodeURIComponent(district)}`;
		if (commodity) url += `&filters[commodity]=${encodeURIComponent(commodity)}`;
		const finalData = (await (await fetch(url)).json()).records || [];
		localStorage.setItem(cacheKey, JSON.stringify({
			data: finalData,
			timestamp: Date.now()
		}));
		return finalData;
	} catch (err) {
		console.error("Mandi API Crash:", err);
		return getMandiMockData(state, district, commodity);
	}
}
