/**
* Fetch top traded commodities for Ticker Tape — with REAL price changes
*/
async function fetchTopTradedCommodities() {
	const cacheKey = `kisanbaba_ticker_data_v4`;
	const cached = localStorage.getItem(cacheKey);
	if (cached) {
		const parsed = JSON.parse(cached);
		if (Date.now() - parsed.timestamp < 18e5) return parsed.data;
	}
	try {
		const data = await (await fetch(`/api/ogd/resource/9ef84268-d588-465a-a308-a864a43d0070?api-key=579b464db66ec23bdd000001b69eb7b556b74d4a7d665f83c03f6fe2&format=json&limit=40&sort[arrival_date]=desc`)).json();
		if (!data.records || data.records.length === 0) return null;
		const commodityMap = {};
		data.records.forEach((r) => {
			const name = r.commodity?.toUpperCase();
			if (!name) return;
			if (!commodityMap[name]) commodityMap[name] = [];
			commodityMap[name].push({
				price: parseInt(r.modal_price || 0),
				date: r.arrival_date,
				market: (r.market || r.district || "Regional Mandi").trim()
			});
		});
		const processed = Object.entries(commodityMap).slice(0, 12).map(([name, records]) => {
			const sorted = records.sort((a, b) => (b.date || "").localeCompare(a.date || ""));
			const latest = sorted[0];
			const previous = sorted.length > 1 ? sorted[1] : null;
			const realChange = previous ? latest.price - previous.price : 0;
			return {
				name,
				mandi: latest.market,
				icon: getIconForName(name),
				price: latest.price,
				change: realChange,
				trend: realChange >= 0 ? "up" : "down"
			};
		}).filter((item) => item.price > 0);
		localStorage.setItem(cacheKey, JSON.stringify({
			data: processed,
			timestamp: Date.now()
		}));
		return processed;
	} catch (e) {
		console.error("Ticker fetch failed:", e);
		return null;
	}
}
function getIconForName(name) {
	const n = name.toLowerCase();
	if (n.includes("tomato")) return "🍅";
	if (n.includes("onion")) return "🧅";
	if (n.includes("potato")) return "🥔";
	if (n.includes("wheat")) return "🌾";
	if (n.includes("paddy") || n.includes("rice")) return "🌾";
	if (n.includes("soyabean")) return "🫘";
	if (n.includes("maize")) return "🌽";
	if (n.includes("chilli")) return "🌶️";
	return "📦";
}
async function fetchMultiDistrictRates(state, district, commodity, userCoords = null) {
	const neighbors = getNeighbors(state, district);
	const { price: originPrice, minPrice: originMin, maxPrice: originMax, date: originDate, isAvailable, market: originMarket } = extractMandiInfo(await fetchMandiRates(state, district, commodity), commodity);
	const neighborPromises = neighbors.map(async (n) => {
		const { price, minPrice, maxPrice, date, isAvailable: nAvailable, market: neighborMarket } = extractMandiInfo(await fetchMandiRates(n.state || state, n.district, commodity), commodity);
		let finalDist = n.distance_km;
		if (userCoords && n.lat && n.lng) finalDist = calculateDistance(userCoords.lat, userCoords.lng, n.lat, n.lng);
		return {
			...n,
			distance_km: finalDist,
			price,
			minPrice,
			maxPrice,
			date,
			isAvailable: nAvailable,
			priceDiff: price - originPrice,
			market: neighborMarket || n.district
		};
	});
	const neighborResults = await Promise.all(neighborPromises);
	return {
		origin: {
			state,
			district,
			market: originMarket || district,
			price: originPrice,
			minPrice: originMin,
			maxPrice: originMax,
			date: originDate,
			commodity,
			isAvailable
		},
		neighbors: neighborResults.filter((n) => n.price > 0),
		dieselRate: DIESEL_RATE_PER_LITRE,
		tractorMileage: TRACTOR_MILEAGE_KM_PER_L
	};
}
function getNeighbors(state, district) {
	if (district_neighbors_default[state] && district_neighbors_default[state][district]) return district_neighbors_default[state][district].slice(0, 8);
	return [];
}
function calculateTransportCost(distanceKm, transportFactor = 1) {
	const litresNeeded = distanceKm * 2 / TRACTOR_MILEAGE_KM_PER_L;
	return Math.round(litresNeeded * DIESEL_RATE_PER_LITRE * transportFactor);
}
function calculateArbitrageProfit(priceDiff, quantityQuintals, distanceKm, transportFactor, districtName, lang = "en") {
	const grossProfit = priceDiff * quantityQuintals;
	const transportCost = calculateTransportCost(distanceKm, transportFactor);
	const netProfit = Math.round(grossProfit - transportCost);
	const isWorthIt = netProfit > 0;
	const empowermentMessage = isWorthIt ? lang === "hi" ? `${districtName} में आज भाव ₹${Math.abs(priceDiff)} ज़्यादा है, और चूंकि यह सिर्फ ${distanceKm} किमी दूर है, यहाँ अपनी फसल ले जाने से आपको डीज़ल के बाद ₹${netProfit.toLocaleString("en-IN")} का अतिरिक्त मुनाफा होगा!` : `${districtName} is paying ₹${Math.abs(priceDiff)} more per quintal today, and since it's only ${distanceKm}km away, driving your tractor there will net you an extra ₹${netProfit.toLocaleString("en-IN")} profit after diesel!` : lang === "hi" ? `${districtName} में भाव ₹${Math.abs(priceDiff)} ज़्यादा है, लेकिन ${distanceKm} किमी की दूरी और डीज़ल खर्च को देखते हुए, स्थानीय मंडी में बेचना ही फायदेमंद है।` : `${districtName} is paying ₹${Math.abs(priceDiff)} more, but after accounting for the ${distanceKm}km drive and diesel costs, you'll save more by selling locally.`;
	return {
		grossProfit: Math.round(grossProfit),
		transportCost,
		netProfit,
		isWorthIt,
		empowermentMessage
	};
}
function extractMandiInfo(data, commodity) {
	if (!data || data.length === 0) return {
		price: 0,
		minPrice: 0,
		maxPrice: 0,
		date: null,
		isAvailable: false,
		market: "Unknown",
		arrivalTonnes: 0
	};
	if (data[0] && data[0].price) {
		const p = data[0].price;
		return {
			price: p,
			minPrice: Math.round(p * .9),
			maxPrice: Math.round(p * 1.1),
			date: (/* @__PURE__ */ new Date()).toLocaleDateString("en-IN"),
			isAvailable: true,
			market: data[0].market || "Main Mandi",
			arrivalTonnes: Math.round(50 + p % 200)
		};
	}
	const match = commodity ? data.find((r) => r.commodity?.toLowerCase().includes(commodity.toLowerCase())) : data[0];
	if (match) {
		const modal = parseInt(match.modal_price || match.price || 0);
		return {
			price: modal,
			minPrice: parseInt(match.min_price || modal * .9),
			maxPrice: parseInt(match.max_price || modal * 1.1),
			date: match.arrival_date || null,
			isAvailable: modal > 0,
			market: match.market || match.mandi_name || "Regional Market",
			arrivalTonnes: parseFloat(match.arrivals_tonnes || match.arrivals || 0)
		};
	}
	const firstModal = data[0]?.modal_price ? parseInt(data[0].modal_price) : 0;
	return {
		price: firstModal,
		minPrice: parseInt(data[0]?.min_price || firstModal * .9),
		maxPrice: parseInt(data[0]?.max_price || firstModal * 1.1),
		date: data[0]?.arrival_date || null,
		isAvailable: firstModal > 0,
		market: data[0]?.market || "Regional Market",
		arrivalTonnes: parseFloat(data[0]?.arrivals_tonnes || data[0]?.arrivals || 0)
	};
}
