/**
* Fetch REAL historical price trend from OGD API
* Falls back to intelligent simulation if historical data is sparse
*/
async function fetchHistoricalTrend(state, district, commodity, currentPrice) {
	const cacheKey = `kisanbaba_trend_${state}_${district}_${commodity}`;
	const cached = localStorage.getItem(cacheKey);
	if (cached) {
		const parsed = JSON.parse(cached);
		if (Date.now() - parsed.timestamp < 36e5) return parsed.data;
	}
	try {
		const url = `/api/ogd/resource/9ef84268-d588-465a-a308-a864a43d0070?api-key=579b464db66ec23bdd000001b69eb7b556b74d4a7d665f83c03f6fe2&format=json&limit=100&filters[state]=${encodeURIComponent(state)}&filters[commodity]=${encodeURIComponent(commodity)}&sort[arrival_date]=desc`;
		const data = await (await fetch(url)).json();
		if (!data.records || data.records.length < 3) return generateSmartTrend(currentPrice, commodity);
		const dateMap = {};
		data.records.forEach((r) => {
			const date = r.arrival_date;
			const price = parseInt(r.modal_price || 0);
			if (date && price > 0) {
				if (!dateMap[date] || price > dateMap[date]) dateMap[date] = price;
			}
		});
		const sorted = Object.entries(dateMap).map(([date, price]) => ({
			date,
			price
		})).sort((a, b) => a.date.localeCompare(b.date)).slice(-30);
		if (sorted.length < 5) return generateSmartTrend(currentPrice, commodity);
		const trend = sorted.map((item) => {
			const parts = item.date.split("/");
			let displayDate;
			try {
				if (parts.length === 3 && parts[2].length === 4) displayDate = new Date(parts[2], parts[1] - 1, parts[0]).toLocaleDateString("en-IN", {
					day: "2-digit",
					month: "short"
				});
				else displayDate = new Date(item.date).toLocaleDateString("en-IN", {
					day: "2-digit",
					month: "short"
				});
			} catch {
				displayDate = item.date;
			}
			return {
				date: displayDate,
				price: item.price,
				isReal: true
			};
		});
		localStorage.setItem(cacheKey, JSON.stringify({
			data: trend,
			timestamp: Date.now()
		}));
		return trend;
	} catch (e) {
		console.error("Historical trend fetch failed:", e);
		return generateSmartTrend(currentPrice, commodity);
	}
}
/**
* Smart trend generation (improved fallback — uses deterministic seed, not random)
*/
function generateSmartTrend(basePrice, commodity) {
	const trend = [];
	const now = /* @__PURE__ */ new Date();
	const seed = (commodity || "crop").split("").reduce((a, c) => a + c.charCodeAt(0), 0);
	let price = basePrice * .92;
	const volatility = [
		"Tomato",
		"Green Chilli",
		"Brinjal",
		"Coriander"
	].some((p) => commodity?.includes(p)) ? .05 : .02;
	for (let i = 29; i >= 0; i--) {
		const date = new Date(now);
		date.setDate(date.getDate() - i);
		const change = (Math.sin((seed + i) * .7) * .5 + Math.cos((seed + i) * 1.3) * .3) * basePrice * volatility;
		price = Math.max(price + change, basePrice * .75);
		price = Math.min(price, basePrice * 1.25);
		trend.push({
			date: date.toLocaleDateString("en-IN", {
				day: "2-digit",
				month: "short"
			}),
			price: Math.round(price),
			isReal: false
		});
	}
	trend[trend.length - 1].price = basePrice;
	return trend;
}
/**
* Calculate distance between two coordinates (Haversine formula)
*/
function calculateDistance(lat1, lon1, lat2, lon2) {
	const R = 6371;
	const dLat = (lat2 - lat1) * Math.PI / 180;
	const dLon = (lon2 - lon1) * Math.PI / 180;
	const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
	const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
	return Math.round(R * c);
}
/**
* Find nearest districts from all-India data given user lat/lng
*/
function findNearestDistricts(userLat, userLng, allDistricts, limit = 5) {
	const flattened = [];
	Object.entries(allDistricts).forEach(([state, distList]) => {
		distList.forEach((d) => {
			flattened.push({
				...d,
				state,
				distance: calculateDistance(userLat, userLng, d.lat, d.lng)
			});
		});
	});
	return flattened.sort((a, b) => a.distance - b.distance).slice(0, limit);
}
function getMandiMockData(state = "", district = "", commodity = "") {
	const seed = district.split("").reduce((a, c) => a + c.charCodeAt(0), 0);
	const basePrices = {
		"Tomato": 1200 + seed % 800,
		"Onion": 1500 + seed % 600,
		"Potato": 800 + seed % 500,
		"Paddy (Dhan)": 2100 + seed % 300,
		"Wheat": 2200 + seed % 400,
		"Soyabean": 4200 + seed % 1e3,
		"Maize": 1800 + seed % 500,
		"Garlic": 3500 + seed % 2e3,
		"Green Chilli": 2e3 + seed % 1500,
		"Brinjal": 1e3 + seed % 700,
		"Cotton": 6200 + seed % 800,
		"Sugarcane": 3100 + seed % 400,
		"Mustard": 4800 + seed % 600,
		"Groundnut": 5200 + seed % 900,
		"Gram (Chana)": 4600 + seed % 500,
		"Moong": 7200 + seed % 800,
		"Arhar (Tur)": 6800 + seed % 700,
		"Urad": 6500 + seed % 600,
		"Turmeric": 8e3 + seed % 3e3,
		"Coriander": 6e3 + seed % 2e3
	};
	if (commodity && basePrices[commodity]) return [{
		id: 1,
		commodity,
		price: basePrices[commodity],
		trend: seed % 2 === 0 ? "up" : "down",
		change: 10 + seed % 150,
		district,
		state
	}];
	return Object.entries(basePrices).slice(0, 5).map(([name, price], i) => ({
		id: i + 1,
		commodity: name,
		price,
		trend: (seed + i) % 3 === 0 ? "down" : "up",
		change: 10 + (seed + i) % 120,
		district,
		state
	}));
}
function getWeatherMockData() {
	return {
		temp: 28,
		humidity: 65,
		windSpeed: 12,
		location: "Raipur, CG",
		icon: "⛅",
		description: "Partly cloudy",
		rainfall: 0,
		feelsLike: 31,
		condition: "Clouds"
	};
}
/**
* Fetch weather for a specific district using its lat/lng (FREE OpenWeatherMap)
*/
async function fetchWeatherForDistrict(lat, lng, districtName) {
	const cacheKey = `kisanbaba_weather_district_${lat}_${lng}`;
	const cached = localStorage.getItem(cacheKey);
	if (cached) {
		const parsed = JSON.parse(cached);
		if (Date.now() - parsed.timestamp < 18e5) return parsed.data;
	}
	try {
		const data = await (await fetch(`https://api.openweathermap.org/data/2.5/weather?lat=${lat}&lon=${lng}&appid=f69b615a57e4d2c2410a340b2d0230a9&units=metric`)).json();
		const weatherData = {
			temp: Math.round(data.main.temp),
			feelsLike: Math.round(data.main.feels_like),
			humidity: data.main.humidity,
			windSpeed: Math.round(data.wind?.speed || 0),
			location: data.name || districtName,
			icon: getWeatherEmoji(data.weather[0]?.main),
			description: data.weather[0]?.description || "Clear",
			condition: data.weather[0]?.main || "Clear",
			rainfall: data.rain?.["1h"] || data.rain?.["3h"] || 0,
			clouds: data.clouds?.all || 0
		};
		localStorage.setItem(cacheKey, JSON.stringify({
			data: weatherData,
			timestamp: Date.now()
		}));
		return weatherData;
	} catch (err) {
		console.error("Weather fetch failed:", err);
		return getWeatherMockData();
	}
}
function getWeatherEmoji(condition) {
	return {
		Clear: "☀️",
		Clouds: "⛅",
		Rain: "🌧️",
		Drizzle: "🌦️",
		Thunderstorm: "⛈️",
		Snow: "❄️",
		Mist: "🌫️",
		Fog: "🌫️",
		Haze: "🌫️",
		Dust: "💨",
		Smoke: "💨",
		Tornado: "🌪️"
	}[condition] || "🌤️";
}
/**
* Calculate spoilage risk for a commodity based on weather
* Returns: { riskLevel: 0-100, riskLabel, advice, hoursToSell }
*/
function getSpoilageRisk(weather, commodity) {
	if (!weather) return {
		riskLevel: 0,
		riskLabel: "Unknown",
		advice: "",
		hoursToSell: 999
	};
	const pFactor = {
		"Tomato": .95,
		"Green Chilli": .9,
		"Brinjal": .85,
		"Onion": .3,
		"Potato": .25,
		"Garlic": .2,
		"Paddy (Dhan)": .1,
		"Wheat": .08,
		"Soyabean": .1,
		"Maize": .15,
		"Cotton": .05,
		"Sugarcane": .7,
		"Mustard": .08,
		"Groundnut": .12,
		"Gram (Chana)": .1,
		"Moong": .1,
		"Arhar (Tur)": .1,
		"Urad": .1,
		"Turmeric": .15,
		"Coriander": .8
	}[commodity] || .5;
	const tempRisk = Math.max(0, (weather.temp - 25) * 3);
	const humidityRisk = Math.max(0, (weather.humidity - 60) * 1.5);
	const rainRisk = weather.rainfall > 0 ? 20 : 0;
	let riskLevel = Math.round((tempRisk + humidityRisk + rainRisk) * pFactor);
	riskLevel = Math.min(100, Math.max(0, riskLevel));
	let riskLabel, advice, hoursToSell;
	if (riskLevel >= 70) {
		riskLabel = "🔴 HIGH RISK";
		advice = `${weather.temp}°C + ${weather.humidity}% humidity = rapid spoilage. Sell within 24 hours!`;
		hoursToSell = 24;
	} else if (riskLevel >= 40) {
		riskLabel = "🟡 MODERATE RISK";
		advice = `Conditions are warm. Sell within 48-72 hours for best quality.`;
		hoursToSell = 72;
	} else if (riskLevel >= 15) {
		riskLabel = "🟢 LOW RISK";
		advice = `Weather is favorable. You can hold for 5-7 days safely.`;
		hoursToSell = 168;
	} else {
		riskLabel = "✅ SAFE";
		advice = `Excellent storage conditions. Hold and wait for better prices.`;
		hoursToSell = 336;
	}
	return {
		riskLevel,
		riskLabel,
		advice,
		hoursToSell
	};
}
/**
* Get weather impact on prices
* Returns: { impact: string, direction: 'up'|'down'|'stable', pctImpact: number, explanation: string }
*/
function getWeatherPriceImpact(weather, commodity) {
	if (!weather) return {
		impact: "Unknown",
		direction: "stable",
		pctImpact: 0,
		explanation: ""
	};
	const isPerishable = [
		"Tomato",
		"Green Chilli",
		"Brinjal",
		"Coriander",
		"Sugarcane"
	].includes(commodity);
	const isGrain = [
		"Wheat",
		"Paddy (Dhan)",
		"Maize",
		"Soyabean",
		"Mustard"
	].includes(commodity);
	let direction = "stable";
	let pctImpact = 0;
	let explanation = "";
	if (weather.rainfall > 5) if (isPerishable) {
		direction = "up";
		pctImpact = Math.round(8 + weather.rainfall * 1.5);
		explanation = `🌧️ Heavy rain disrupts harvesting & transport. ${commodity} supply will drop. Price likely to RISE ${pctImpact}%.`;
	} else {
		direction = "up";
		pctImpact = Math.round(3 + weather.rainfall * .5);
		explanation = `🌧️ Rain may delay arrivals at mandi. Slight price increase expected.`;
	}
	else if (weather.temp > 40) {
		if (isPerishable) {
			direction = "down";
			pctImpact = Math.round((weather.temp - 38) * 3);
			explanation = `🌡️ Extreme heat (${weather.temp}°C) accelerates spoilage. Farmers rush to sell. Prices may DIP ${pctImpact}%.`;
		}
	} else if (weather.rainfall > 0 && weather.rainfall <= 5) if (isGrain) {
		direction = "down";
		pctImpact = 3;
		explanation = `🌦️ Light rain is favorable for standing ${commodity} crop. Future supply will be strong. Prices may soften.`;
	} else {
		direction = "stable";
		pctImpact = 0;
		explanation = `🌤️ Light showers have minimal impact on ${commodity} pricing today.`;
	}
	else if (weather.condition === "Clear" && weather.temp < 35) {
		direction = "stable";
		pctImpact = 0;
		explanation = `☀️ Clear weather with normal temperatures. Markets functioning normally. Prices expected to remain STABLE.`;
	} else if (weather.temp >= 35 && weather.temp <= 40) {
		if (isPerishable) {
			direction = "up";
			pctImpact = Math.round((weather.temp - 33) * 1.5);
			explanation = `🌡️ Warm weather (${weather.temp}°C) may reduce ${commodity} shelf life. Early arrivals get better prices.`;
		}
	}
	if (!explanation) explanation = `${weather.icon} ${weather.description}. No significant price impact expected for ${commodity}.`;
	return {
		impact: pctImpact > 5 ? "HIGH" : pctImpact > 0 ? "MODERATE" : "LOW",
		direction,
		pctImpact,
		explanation
	};
}
/**
* Get sell timing advice based on weather + price trend
*/
function getSellTimingAdvice(weather, spoilageRisk, commodity, currentPrice, trendData) {
	const isTrending = trendData && trendData.length > 1;
	const lastPrice = isTrending ? trendData[trendData.length - 1].price : currentPrice;
	const weekAgoPrice = isTrending && trendData.length > 7 ? trendData[trendData.length - 7].price : currentPrice;
	const weekTrend = weekAgoPrice > 0 ? (lastPrice - weekAgoPrice) / weekAgoPrice * 100 : 0;
	if (spoilageRisk.riskLevel >= 70) return {
		action: "SELL NOW",
		emoji: "🚨",
		reason: `High spoilage risk! ${weather.temp}°C + ${weather.humidity}% humidity.`,
		urgency: "critical",
		logic: [
			"High Spoilage Risk: Weather is too hot/humid for storage.",
			`Urgency: ${commodity} will start losing weight/quality in ${spoilageRisk.hoursToSell} hours.`,
			"Maximize Value: Selling now prevents 100% loss later."
		]
	};
	if (weekTrend > 3 && spoilageRisk.riskLevel < 40) return {
		action: "HOLD 2-3 DAYS",
		emoji: "📈",
		reason: `Price up ${weekTrend.toFixed(1)}% this week + good weather.`,
		urgency: "low",
		logic: [
			`Market Momentum: Prices rose ${weekTrend.toFixed(1)}% in 7 days, likely to peak further.`,
			"Safe Storage: Weather is dry and cool, crop won't spoil if held.",
			"Profit Goal: Waiting 48 hours could net 2-3% more profit."
		]
	};
	if (weekTrend < -3) return {
		action: "SELL SOON",
		emoji: "⏰",
		reason: `Price dropped ${Math.abs(weekTrend).toFixed(1)}% this week.`,
		urgency: "high",
		logic: [
			`Downward Trend: Market is softening (${weekTrend.toFixed(1)}% drop). Don't wait for bottom.`,
			"Supply Surge: Many farmers are bringing stock, causing a price dip.",
			"Risk Mitigation: Lock in current profit before it falls further."
		]
	};
	return {
		action: "SELL THIS WEEK",
		emoji: "✅",
		reason: `Market is stable. Weather is ${weather.icon} ${weather.description}.`,
		urgency: "medium",
		logic: [
			"Stable Prices: No big movements expected in next 3 days.",
			"Fair Value: Current price is near the 7-day average.",
			"Convenience: Sell at your ease without rushing or waiting."
		]
	};
}
