/**
* KisanBaba RSS Feed Utility for Authentic Govt Updates (PIB)
*/
var AGRI_KEYWORDS = [
	"MSP",
	"Minimum Support Price",
	"Agriculture",
	"Kisan",
	"Farmer",
	"Mandi",
	"Crop",
	"CCEA",
	"Cabinet",
	"Agmarknet"
];
/**
* Fetch and parse latest agriculture policy news from PIB (Press Information Bureau)
* @param {string} lang - 'en' or 'hi'
* @returns {Promise<Array>} - List of news items
*/
async function fetchAgriNews(lang = "en") {
	const cacheKey = `kisanbaba_news_${lang}`;
	const cached = localStorage.getItem(cacheKey);
	if (cached) {
		const parsed = JSON.parse(cached);
		if (Date.now() - parsed.timestamp < 36e5) return parsed.data;
	}
	try {
		const text = await (await fetch(`/api/pib/RssMain.aspx?ModId=6&Lang=${lang === "hi" ? "2" : "1"}&Regid=${lang === "hi" ? "3" : "1"}`)).text();
		const items = new DOMParser().parseFromString(text, "text/xml").querySelectorAll("item");
		const news = [];
		items.forEach((item) => {
			const title = item.querySelector("title")?.textContent || "";
			const description = item.querySelector("description")?.textContent || "";
			const link = item.querySelector("link")?.textContent || "";
			const pubDate = item.querySelector("pubDate")?.textContent || "";
			if (AGRI_KEYWORDS.some((kw) => title.toLowerCase().includes(kw.toLowerCase()) || description.toLowerCase().includes(kw.toLowerCase()))) news.push({
				title,
				description: description.replace(/<[^>]*>?/gm, "").slice(0, 160) + "...",
				link,
				date: new Date(pubDate).toLocaleDateString("en-IN", {
					day: "2-digit",
					month: "short",
					year: "numeric"
				}),
				source: "PIB (Govt of India)"
			});
		});
		const finalData = news.length > 0 ? news : Array.from(items).slice(0, 5).map((item) => ({
			title: item.querySelector("title")?.textContent || "",
			description: (item.querySelector("description")?.textContent || "").replace(/<[^>]*>?/gm, "").slice(0, 160) + "...",
			link: item.querySelector("link")?.textContent || "",
			date: new Date(item.querySelector("pubDate")?.textContent || "").toLocaleDateString("en-IN", {
				day: "2-digit",
				month: "short",
				year: "numeric"
			}),
			source: "PIB (Govt of India)"
		}));
		localStorage.setItem(cacheKey, JSON.stringify({
			data: finalData,
			timestamp: Date.now()
		}));
		return finalData;
	} catch (error) {
		console.error("PIB RSS Fetch Error:", error);
		return [];
	}
}
